"""HTTP server implementation for webcore.

This module provides the main WebServer class that handles HTTP requests,
route matching, middleware execution, and hot reload support for development.
"""
import socket
import threading
import logging
import time
import json
from typing import Callable, Optional
from .config import Config, hot_reload_enabled

logger = logging.getLogger(__name__)


class Route:
    """Represents a single URL route."""

    def __init__(self, path: str, handler: Callable, methods: list[str] = None):
        self.path = path
        self.handler = handler
        self.methods = methods or ["GET"]

    def matches(self, request_path: str, method: str) -> bool:
        return self.path == request_path and method in self.methods


class Request:
    """Simplified HTTP request object."""

    def __init__(self, method: str, path: str, headers: dict = None, body: str = ""):
        self.method = method
        self.path = path
        self.headers = headers or {}
        self.body = body
        self.params = {}

    @classmethod
    def from_raw(cls, raw: str) -> "Request":
        lines = raw.strip().split("\r\n")
        if not lines:
            return cls("GET", "/")
        first_line = lines[0].split(" ")
        method = first_line[0] if len(first_line) > 0 else "GET"
        path = first_line[1] if len(first_line) > 1 else "/"
        headers = {}
        body = ""
        in_body = False
        for line in lines[1:]:
            if in_body:
                body += line
            elif line == "":
                in_body = True
            else:
                parts = line.split(": ", 1)
                if len(parts) == 2:
                    headers[parts[0].lower()] = parts[1]
        return cls(method, path, headers, body)


class Response:
    """Simplified HTTP response object."""

    def __init__(self, status: int = 200, body: str = "", content_type: str = "text/plain"):
        self.status = status
        self.body = body
        self.content_type = content_type
        self.headers = {}

    def to_bytes(self) -> bytes:
        status_text = {200: "OK", 404: "Not Found", 500: "Internal Server Error"}
        status_line = f"HTTP/1.1 {self.status} {status_text.get(self.status, 'Unknown')}"
        headers = f"Content-Type: {self.content_type}\r\nContent-Length: {len(self.body)}"
        for k, v in self.headers.items():
            headers += f"\r\n{k}: {v}"
        return f"{status_line}\r\n{headers}\r\n\r\n{self.body}".encode()

    @classmethod
    def json(cls, data: dict, status: int = 200) -> "Response":
        return cls(status=status, body=json.dumps(data), content_type="application/json")

    @classmethod
    def not_found(cls) -> "Response":
        return cls(status=404, body="Not Found")

    @classmethod
    def error(cls, message: str) -> "Response":
        return cls(status=500, body=message)


class WebServer:
    """Main HTTP server for the webcore framework.

    Supports route registration, middleware chains, graceful shutdown,
    and optional hot reload for development environments.
    """

    def __init__(self, config: Config = None):
        self.config = config or Config()
        self.routes: list[Route] = []
        self.middleware: list[Callable] = []
        self._running = False
        self._server_socket: Optional[socket.socket] = None
        self._threads: list[threading.Thread] = []
        self._request_count = 0
        self._start_time = None

    def route(self, path: str, methods: list[str] = None) -> Callable:
        """Decorator to register a route handler."""
        def decorator(fn):
            self.routes.append(Route(path, fn, methods))
            return fn
        return decorator

    def add_middleware(self, fn: Callable) -> None:
        """Add a middleware function to the processing chain."""
        self.middleware.append(fn)

    def _find_route(self, path: str, method: str) -> Optional[Route]:
        for route in self.routes:
            if route.matches(path, method):
                return route
        return None

    def _apply_middleware(self, request: Request) -> Request:
        for mw in self.middleware:
            request = mw(request)
        return request

    def handle_request(self, request: Request) -> Response:
        """Process a single HTTP request through middleware and routing."""
        try:
            request = self._apply_middleware(request)
            route = self._find_route(request.path, request.method)
            if route is None:
                return Response.not_found()
            result = route.handler(request)
            if isinstance(result, Response):
                return result
            if isinstance(result, dict):
                return Response.json(result)
            return Response(body=str(result))
        except Exception as e:
            logger.error(f"Error handling request: {e}")
            return Response.error(str(e))

    # Hot reload support
    def _start_watcher(self):
        """Start the file watcher thread for hot reload."""
        try:
            from .watcher import FileWatcher
            watch_dir = self.config.get("watch_dir", ".")
            self._watcher = FileWatcher(watch_dir, callback=self._on_file_change)
            watcher_thread = threading.Thread(
                target=self._watcher.run,
                name="hot-reload-watcher",
                daemon=True,
            )
            watcher_thread.start()
            self._threads.append(watcher_thread)
            logger.info("Hot reload watcher started on %s", watch_dir)
        except ImportError:
            logger.warning("Hot reload watcher not available")

    def _on_file_change(self, path: str):
        """Callback when a watched file changes (triggers reload)."""
        logger.info(f"File changed: {path}, triggering hot reload")
        self.stop()

    def start(self, host: str = "127.0.0.1", port: int = 8000):
        """Start the HTTP server.

        If hot_reload is enabled in the configuration, a file watcher thread
        is also started to monitor source files for changes.
        """
        self._running = True
        self._start_time = time.time()
        logger.info(f"Starting webcore server on {host}:{port}")

        if hot_reload_enabled(self.config):
            self._start_watcher()
            logger.info("Hot reload is enabled")

        self._server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self._server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self._server_socket.settimeout(1.0)
        self._server_socket.bind((host, port))
        self._server_socket.listen(self.config.get("backlog", 5))

        logger.info(f"Server listening on {host}:{port}")

        while self._running:
            try:
                client, addr = self._server_socket.accept()
                thread = threading.Thread(
                    target=self._handle_client,
                    args=(client, addr),
                    daemon=True,
                )
                thread.start()
            except socket.timeout:
                continue
            except OSError:
                break

    def _handle_client(self, client: socket.socket, addr: tuple):
        """Handle a single client connection."""
        try:
            raw = client.recv(4096).decode("utf-8", errors="replace")
            request = Request.from_raw(raw)
            response = self.handle_request(request)
            client.sendall(response.to_bytes())
            self._request_count += 1
        except Exception as e:
            logger.error(f"Client handler error: {e}")
        finally:
            client.close()

    def stop(self):
        """Gracefully stop the server."""
        self._running = False
        if self._server_socket:
            try:
                self._server_socket.close()
            except OSError:
                pass
        logger.info("Server stopped")

    @property
    def stats(self) -> dict:
        """Return server statistics."""
        uptime = time.time() - self._start_time if self._start_time else 0
        return {
            "requests_served": self._request_count,
            "uptime_seconds": round(uptime, 2),
            "routes_registered": len(self.routes),
            "middleware_count": len(self.middleware),
        }


def create_app(config: Config = None) -> WebServer:
    """Factory function to create a configured WebServer instance."""
    server = WebServer(config)

    @server.route("/health")
    def health(req):
        return {"status": "ok"}

    @server.route("/stats")
    def stats(req):
        return server.stats

    return server

