"""Configuration management for webcore.

Handles loading, merging, and accessing configuration values.
Supports file-based config (JSON) with environment variable overrides.
"""
import json
import os
from typing import Any, Optional

# Default configuration values
DEFAULT_CONFIG = {
    "host": "127.0.0.1",
    "port": 8000,
    "backlog": 5,
    "timeout": 30,
    "log_level": "INFO",
    "max_request_size": 1048576,
    # Hot reload configuration
    "hot_reload": True,
    "watch_dir": ".",
    "watch_extensions": [".py", ".html", ".css"],
    "static_dir": "static",
    "template_dir": "templates",
}


class Config:
    """Application configuration container."""

    def __init__(self, config_path: Optional[str] = None, **overrides):
        self._data = dict(DEFAULT_CONFIG)
        if config_path and os.path.exists(config_path):
            with open(config_path) as f:
                self._data.update(json.load(f))
        # Environment variable overrides
        for key in ["host", "port", "log_level"]:
            env_val = os.environ.get(f"WEBCORE_{key.upper()}")
            if env_val is not None:
                self._data[key] = int(env_val) if key == "port" else env_val
        self._data.update(overrides)

    def get(self, key: str, default: Any = None) -> Any:
        return self._data.get(key, default)

    def set(self, key: str, value: Any) -> None:
        self._data[key] = value

    @property
    def host(self) -> str:
        return self._data["host"]

    @property
    def port(self) -> int:
        return self._data["port"]

    @property
    def hot_reload_enabled(self) -> bool:
        """Check if hot reload is enabled in the configuration."""
        return bool(self._data.get("hot_reload", False))

    @property
    def log_level(self) -> str:
        return self._data.get("log_level", "INFO")

    def to_dict(self) -> dict:
        return dict(self._data)


def load_config(path: str = "config.json") -> Config:
    """Load configuration from a JSON file."""
    return Config(config_path=path)


def hot_reload_enabled(config: Config) -> bool:
    """Module-level helper to check if hot reload is enabled."""
    return config.hot_reload_enabled

