"""File system watcher for hot reload.

Monitors a directory tree for file changes and triggers a callback
when source files are modified. Used by the server to implement
hot reload during development.
"""
import os
import time
import logging
from typing import Callable, Optional

logger = logging.getLogger(__name__)


class FileWatcher:
    """Watch a directory for file changes.

    Polls the filesystem at a configurable interval and invokes a
    callback when any watched file's mtime changes.
    """

    def __init__(
        self,
        directory: str,
        extensions: list[str] = None,
        interval: float = 1.0,
        callback: Optional[Callable[[str], None]] = None,
    ):
        self.directory = os.path.abspath(directory)
        self.extensions = extensions or [".py", ".html", ".css"]
        self.interval = interval
        self.callback = callback
        self._running = False
        self._file_mtimes: dict[str, float] = {}

    def _scan(self) -> dict[str, float]:
        """Scan the directory and return a dict of file -> mtime."""
        result = {}
        for root, dirs, files in os.walk(self.directory):
            # Skip hidden directories and __pycache__
            dirs[:] = [d for d in dirs if not d.startswith(".") and d != "__pycache__"]
            for fname in files:
                if any(fname.endswith(ext) for ext in self.extensions):
                    fpath = os.path.join(root, fname)
                    try:
                        result[fpath] = os.path.getmtime(fpath)
                    except OSError:
                        pass
        return result

    def _check_changes(self) -> list[str]:
        """Check for changed files since last scan."""
        current = self._scan()
        changed = []
        for path, mtime in current.items():
            if path not in self._file_mtimes or self._file_mtimes[path] < mtime:
                changed.append(path)
        self._file_mtimes = current
        return changed

    def run(self):
        """Start the watcher loop. Blocks until stop() is called."""
        self._running = True
        self._file_mtimes = self._scan()
        logger.info(f"Watching {self.directory} for changes ({len(self._file_mtimes)} files)")

        while self._running:
            time.sleep(self.interval)
            changed = self._check_changes()
            for path in changed:
                logger.info(f"Detected change: {path}")
                if self.callback:
                    try:
                        self.callback(path)
                    except Exception as e:
                        logger.error(f"Watcher callback error: {e}")

    def stop(self):
        """Stop the watcher loop."""
        self._running = False

    @property
    def watched_files(self) -> int:
        """Return number of files being watched."""
        return len(self._file_mtimes)
